INSERT INTO `evaluations` VALUES (991, '中文语法结构', '每题有一个句子，均用斜线分成四个部分。假如A部分在文法或用词上有错误，请点选A，B部分有错就选B，以此类推。', '', 1, 176, 0, '中文语法结构', 0, 'B', '', '[{\"name\": \"A\", \"parse\": \"妈妈头发散乱、眼睛红肿，/\"}, {\"name\": \"B\", \"parse\": \"脸色布满一串串泪痕，/\"}, {\"name\": \"C\", \"parse\": \"而且脸色憔悴，/\"}, {\"name\": \"D\", \"parse\": \"一夜之间好像苍老了许多。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
INSERT INTO `evaluations` VALUES (992, '中文语法结构', '每题有一个句子，均用斜线分成四个部分。假如A部分在文法或用词上有错误，请点选A，B部分有错就选B，以此类推。', '', 1, 177, 0, '中文语法结构', 0, 'D', '', '[{\"name\": \"A\", \"parse\": \"老王日日山珍海味、/\"}, {\"name\": \"B\", \"parse\": \"食前方丈、/\"}, {\"name\": \"C\", \"parse\": \"穷奢极侈，/\"}, {\"name\": \"D\", \"parse\": \"享尽人间的菽水之欢。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
INSERT INTO `evaluations` VALUES (993, '中文语法结构', '每题有一个句子，均用斜线分成四个部分。假如A部分在文法或用词上有错误，请点选A，B部分有错就选B，以此类推。', '', 1, 178, 0, '中文语法结构', 0, 'B', '', '[{\"name\": \"A\", \"parse\": \"对这件耸人听闻的事件起因，大家众说纷云，/\"}, {\"name\": \"B\", \"parse\": \"强聒不舍，/\"}, {\"name\": \"C\", \"parse\": \"最好不要道听涂说，/\"}, {\"name\": \"D\", \"parse\": \"以免三人成虎。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
INSERT INTO `evaluations` VALUES (994, '中文语法结构', '每题有一个句子，均用斜线分成四个部分。假如A部分在文法或用词上有错误，请点选A，B部分有错就选B，以此类推。', '', 1, 179, 0, '中文语法结构', 0, 'D', '', '[{\"name\": \"A\", \"parse\": \"因为平素表现秀异，/\"}, {\"name\": \"B\", \"parse\": \"被膺选为模范代表，/\"}, {\"name\": \"C\", \"parse\": \"他心中兴奋莫名，/\"}, {\"name\": \"D\", \"parse\": \"寝不安席。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
INSERT INTO `evaluations` VALUES (995, '中文语法结构', '每题有一个句子，均用斜线分成四个部分。假如A部分在文法或用词上有错误，请点选A，B部分有错就选B，以此类推。', '', 1, 180, 0, '中文语法结构', 0, 'D', '', '[{\"name\": \"A\", \"parse\": \"主席报告：理学院院长因故耽搁，/\"}, {\"name\": \"B\", \"parse\": \"将会迟一些莅临会场。/\"}, {\"name\": \"C\", \"parse\": \"等会儿他来了，/\"}, {\"name\": \"D\", \"parse\": \"我们一定请他到台前来，让大家瞻仰一下。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
INSERT INTO `evaluations` VALUES (996, '中文语法结构', '每题有一个句子，均用斜线分成四个部分。假如A部分在文法或用词上有错误，请点选A，B部分有错就选B，以此类推。', '', 1, 181, 0, '中文语法结构', 0, 'B', '', '[{\"name\": \"A\", \"parse\": \"老林幽默感十足，/\"}, {\"name\": \"B\", \"parse\": \"每一次都口若悬河，/\"}, {\"name\": \"C\", \"parse\": \"令在场每个人，/\"}, {\"name\": \"D\", \"parse\": \"都笑声频频。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
INSERT INTO `evaluations` VALUES (997, '中文语法结构', '每题有一个句子，均用斜线分成四个部分。假如A部分在文法或用词上有错误，请点选A，B部分有错就选B，以此类推。', '', 1, 182, 0, '中文语法结构', 0, 'D', '', '[{\"name\": \"A\", \"parse\": \"我和同学前往文化中心/\"}, {\"name\": \"B\", \"parse\": \"参观花卉展览，/\"}, {\"name\": \"C\", \"parse\": \"品种繁多，琳琅满目/\"}, {\"name\": \"D\", \"parse\": \"真是令我矛塞顿开。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
INSERT INTO `evaluations` VALUES (998, '中文语法结构', '每题有一个句子，均用斜线分成四个部分。假如A部分在文法或用词上有错误，请点选A，B部分有错就选B，以此类推。', '', 1, 183, 0, '中文语法结构', 0, 'D', '', '[{\"name\": \"A\", \"parse\": \"接着为您播报地震救灾的后续消息。/\"}, {\"name\": \"B\", \"parse\": \"以下，/\"}, {\"name\": \"C\", \"parse\": \"是本台记者在灾变现场的报导，/\"}, {\"name\": \"D\", \"parse\": \"请观众先看一段现场的精彩画面。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
INSERT INTO `evaluations` VALUES (999, '中文语法结构', '每题有一个句子，均用斜线分成四个部分。假如A部分在文法或用词上有错误，请点选A，B部分有错就选B，以此类推。', '', 1, 184, 0, '中文语法结构', 0, 'D', '', '[{\"name\": \"A\", \"parse\": \"春和景明，/\"}, {\"name\": \"B\", \"parse\": \"驱车上山，/\"}, {\"name\": \"C\", \"parse\": \"徜徉在苍松翠柏间，/\"}, {\"name\": \"D\", \"parse\": \"彷佛自己是绿林好汉。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
INSERT INTO `evaluations` VALUES (1000, '中文语法结构', '每题有一个句子，均用斜线分成四个部分。假如A部分在文法或用词上有错误，请点选A，B部分有错就选B，以此类推。', '', 1, 185, 0, '中文语法结构', 0, 'D', '', '[{\"name\": \"A\", \"parse\": \"火虽然是日常生活中不可缺少的东西，/\"}, {\"name\": \"B\", \"parse\": \"但火警发生的时候，/\"}, {\"name\": \"C\", \"parse\": \"它的灾害比洪水猛兽/\"}, {\"name\": \"D\", \"parse\": \"还更勇猛。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
INSERT INTO `evaluations` VALUES (1001, '中文语法结构', '每题有一个句子，均用斜线分成四个部分。假如A部分在文法或用词上有错误，请点选A，B部分有错就选B，以此类推。', '', 1, 186, 0, '中文语法结构', 0, 'D', '', '[{\"name\": \"A\", \"parse\": \"十九岁是一篇美妙的乐章，/\"}, {\"name\": \"B\", \"parse\": \"谱出的是，/\"}, {\"name\": \"C\", \"parse\": \"生命最美妙的/\"}, {\"name\": \"D\", \"parse\": \"色彩。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
INSERT INTO `evaluations` VALUES (1002, '中文语法结构', '每题有一个句子，均用斜线分成四个部分。假如A部分在文法或用词上有错误，请点选A，B部分有错就选B，以此类推。', '', 1, 187, 0, '中文语法结构', 0, 'D', '', '[{\"name\": \"A\", \"parse\": \"考古学家在周口店/\"}, {\"name\": \"B\", \"parse\": \"发现史前人类遗址，/\"}, {\"name\": \"C\", \"parse\": \"经过鉴定，/\"}, {\"name\": \"D\", \"parse\": \"应该是北平了。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
