INSERT INTO `evaluations` VALUES (1219, '下面那一种「自我介绍」最能代表你自己？', '只能选一种「自我介绍」代表你自己，你最想选那一种？', '', 1, 404, 2, '生涯兴趣', 0, '', '', '[{\"name\": \"A\", \"parse\": \"我有操作机械的能力，倾向自己独立完成工作，避免做些常常与人沟通的事。爱动手操弄，喜欢做和机械、工具、电器、户外有关的工作。我认为自己是勤奋的技术家，期望从事机械、电子、土木建筑、工程技术等工作。\"}, {\"name\": \"B\", \"parse\": \"我有分析推理的能力，倾向自己思考解决问题，胜过在商场或政界发展。喜欢观察、分析、探究和研发的工作，我认为自己是客观的科学家，期望从事物理、生物、化学、医药、数学、地科等相关工作。\"}, {\"name\": \"C\", \"parse\": \"我乐于助人、善解人意并具洞察力，倾向与人接触胜过操作机械仪器，喜欢协助他人增进知识与技能、健全身心健康与信念。我认为自己是教育或心理学家，期望从事教师、咨商辅导、社会救助、健康照护等相关工作。\"}, {\"name\": \"D\", \"parse\": \"我有敏捷文书整理或计算能力，倾向在有清楚规范的环境下工作，胜过创作或研究工作，喜欢有调理的将文书、数字与物品归类管理。我认为自己是谨慎的事务家。期望从事财务、金融、会计、物流管理等工作\"}, {\"name\": \"E\", \"parse\": \"我有艺术创作的能力，倾向运用想象力，胜过快速计算或物品归类。喜欢藉文字、声音、色彩或形式来表达美感创作。我认为自己是表现美的艺术家，期望从事音乐、写作、戏剧、绘画、设计、舞蹈等工作。\"}, {\"name\": \"F\", \"parse\": \"我有领导、说服他人的能力，倾向在法政与商界工作，胜过基础科学研究。喜欢影响他人，获取相当的报酬。我认为自己是有自信的事业家，期望未来从事管理、销售、司法、从政等工作。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
INSERT INTO `evaluations` VALUES (1220, '下面那一种「自我介绍」最能代表你自己？', '让您再选一种「自我介绍」代表你自己，你会选那一种？', '', 1, 405, 2, '生涯兴趣', 0, '', '', '[{\"name\": \"A\", \"parse\": \"我有操作机械的能力，倾向自己独立完成工作，避免做些常常与人沟通的事。爱动手操弄，喜欢做和机械、工具、电器、户外有关的工作。我认为自己是勤奋的技术家，期望从事机械、电子、土木建筑、工程技术等工作。\"}, {\"name\": \"B\", \"parse\": \"我有分析推理的能力，倾向自己思考解决问题，胜过在商场或政界发展。喜欢观察、分析、探究和研发的工作，我认为自己是客观的科学家，期望从事物理、生物、化学、医药、数学、地科等相关工作。\"}, {\"name\": \"C\", \"parse\": \"我乐于助人、善解人意并具洞察力，倾向与人接触胜过操作机械仪器，喜欢协助他人增进知识与技能、健全身心健康与信念。我认为自己是教育或心理学家，期望从事教师、咨商辅导、社会救助、健康照护等相关工作。\"}, {\"name\": \"D\", \"parse\": \"我有敏捷文书整理或计算能力，倾向在有清楚规范的环境下工作，胜过创作或研究工作，喜欢有调理的将文书、数字与物品归类管理。我认为自己是谨慎的事务家。期望从事财务、金融、会计、物流管理等工作\"}, {\"name\": \"E\", \"parse\": \"我有艺术创作的能力，倾向运用想象力，胜过快速计算或物品归类。喜欢藉文字、声音、色彩或形式来表达美感创作。我认为自己是表现美的艺术家，期望从事音乐、写作、戏剧、绘画、设计、舞蹈等工作。\"}, {\"name\": \"F\", \"parse\": \"我有领导、说服他人的能力，倾向在法政与商界工作，胜过基础科学研究。喜欢影响他人，获取相当的报酬。我认为自己是有自信的事业家，期望未来从事管理、销售、司法、从政等工作。\"}]', '2025-12-19 13:05:07', '2025-12-19 13:05:07');
